#include <stdio.h>
#include <math.h>
#include <float.h>

typedef struct {
    double x, y;
} Point;

void readPointsFromFile(const char* filename, Point points[], int* count) {
    FILE* file = fopen(filename, "r");
    if (file == NULL) {
        printf("Error opening file.\n");
        return;
    }

    *count = 0;
    while (fscanf(file, "%lf %lf", &points[*count].x, &points[*count].y) == 2) {
        (*count)++;
    }

    fclose(file);
}

void printPoints(Point points[], int count) {
    for (int i = 0; i < count; i++) {
        printf("(%.2f, %.2f)", points[i].x, points[i].y);
        if (i != count - 1) {
            printf(", ");
        }
    }
}

double distance(Point p1, Point p2) {
    return sqrt(pow(p1.x - p2.x, 2) + pow(p1.y - p2.y, 2));
}

void findFarthestAndClosestPoints(Point points[], int count) {
    if (count < 2) {
        printf("Not enough points to determine farthest and closest pairs.\n");
        return;
    }

    double maxDistance = -DBL_MAX;
    double minDistance = DBL_MAX;
    Point farthestPair[2];
    Point closestPair[2];

    for (int i = 0; i < count; i++) {
        for (int j = i + 1; j < count; j++) {
            double dist = distance(points[i], points[j]);
            if (dist > maxDistance) {
                maxDistance = dist;
                farthestPair[0] = points[i];
                farthestPair[1] = points[j];
            }
            if (dist < minDistance) {
                minDistance = dist;
                closestPair[0] = points[i];
                closestPair[1] = points[j];
            }
        }
    }

    printf("Farthest pair: (%.2f, %.2f) and (%.2f, %.2f) with distance %.6f\n",
           farthestPair[0].x, farthestPair[0].y,
           farthestPair[1].x, farthestPair[1].y,
           maxDistance);

